async function* asyncGenerator() {
  const data = [1000, 2000, 1500];
  for (const delay of data) {
    // Simulate an async operation with a delay
    await new Promise(resolve => setTimeout(resolve, delay));
    yield `Waited for ${delay} ms`;
  }
}

(async () => {
  for await (const message of asyncGenerator()) {
    console.log(message);
  }
})();

async function* fetchUrls(urls) {
  for (const url of urls) {
    const response = await fetch(url);
    const text = await response.text();
    yield text;
  }
}

(async () => {
  const urls = [
    'https://jsonplaceholder.typicode.com/posts/1',
    'https://jsonplaceholder.typicode.com/posts/2'
  ];
  for await (const content of fetchUrls(urls)) {
    console.log('Fetched content length:', content.length);
  }
})();

async function processStream(stream) {
  const reader = stream.getReader();
  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    console.log('Received chunk:', new TextDecoder().decode(value));
  }
}

async function processStreamAsync(stream) {
  for await (const chunk of stream) {
    console.log('Received chunk:', new TextDecoder().decode(chunk));
  }
}

const fetchData = () => {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      const success = Math.random() > 0.5;
      if (success) {
        resolve('Data fetched successfully');
      } else {
        reject(new Error('Fetch failed'));
      }
    }, 1000);
  });
};

fetchData()
  .then(data => {
    console.log(data);
  })
  .catch(error => {
    console.error('Error:', error.message);
  });

async function getData() {
  try {
    const data = await fetchData();
    console.log(data);
  } catch (error) {
    console.error('Caught error:', error.message);
  }
}

getData();

const promise1 = Promise.resolve('Success 1');
const promise2 = Promise.reject(new Error('Failed 2'));
const promise3 = new Promise(resolve => setTimeout(() => resolve('Success 3'), 500));

Promise.allSettled([promise1, promise2, promise3])
  .then(results => {
    results.forEach((result, index) => {
      if (result.status === 'fulfilled') {
        console.log(`Promise ${index + 1} succeeded with:`, result.value);
      } else {
        console.log(`Promise ${index + 1} failed with:`, result.reason.message);
      }
    });
  });

const to = promise => promise.then(data => [null, data]).catch(err => [err, null]);

async function fetchWithTo() {
  const [error, data] = await to(fetchData());
  if (error) {
    console.error('Error captured with to():', error.message);
  } else {
    console.log('Data received:', data);
  }
}

fetchWithTo();

